/**
 * @param {number} n
 * @param {number[][]} edges
 * @param {number} source
 * @param {number} target
 * @param {number} k
 * @return {number}
 */
function solve(n, edges, source, target, k) {
    if (source === target) {
        return 0;
    }

    // 1. Collect all unique edge weights to define search space
    const weights = new Set();
    for (const [, , w] of edges) {
        weights.add(w);
    }
    // Include 0 as a possible threshold, though usually covered if min weight is 1.
    // The smallest possible answer is 0 if any path exists with only light edges (weight <= 0, which is impossible by constraints, but 0 is a lower bound).
    weights.add(0); 

    const sortedWeights = Array.from(weights).sort((a, b) => a - b);

    // 2. Define the check function: can we reach target from source with at most k heavy edges if threshold is T?
    /**
     * Checks if a path exists from source to target using at most k heavy edges
     * given a threshold T.
     * @param {number} T - The current threshold.
     * @returns {boolean} - True if a valid path exists, false otherwise.
     */
    const canReach = (T) => {
        // Build the adjacency list for the current threshold T
        const adj = Array(n).fill(0).map(() => []);
        for (const [u, v, w] of edges) {
            // Cost: 0 if light (w <= T), 1 if heavy (w > T)
            const cost = w > T ? 1 : 0;

            // Since we are looking for minimum heavy edges, this is a shortest path problem
            // where the 'length' is the number of heavy edges.
            // We use BFS/Dijkstra tailored for 0/1 edge weights.
            adj[u].push({ neighbor: v, cost: cost });
            adj[v].push({ neighbor: u, cost: cost });
        }

        // State: [node, heavy_edges_count]
        // dist[i][j] = minimum heavy edges to reach node i using exactly j heavy edges.
        // Since we only care if it's <= k, we can use Dijkstra/0-1 BFS variant.

        // dist[i] stores the minimum number of heavy edges to reach node i.
        // Initialize with infinity.
        const dist = Array(n).fill(Infinity);

        // Priority Queue stores [heavy_edges_count, node]
        // We use a standard array simulating a min-heap for simplicity, as N is small (1000).
        // For N=1000, Dijkstra complexity O(E log V) or O(V^2) is acceptable.
        // Here, the state space is (N * (K+1)), which is small enough.

        // Using Dijkstra on the state space (node, heavy_count)
        // dist[i][j] = true if node i is reachable with exactly j heavy edges. (Boolean reachability is enough)
        // Or, better: dist[i] = minimum heavy edges to reach node i.

        // Let's use the definition: dist[i] is the minimum number of heavy edges to reach i.
        // Since we need *at most* k, we need to track the cost explicitly.

        // dist[i] = minimum number of heavy edges to reach node i.
        // Initialize: dist[source] = 0, others = Infinity
        const minHeavyEdges = Array(n).fill(Infinity);
        minHeavyEdges[source] = 0;

        // Simple Dijkstra implementation using a min-priority queue
        // Stores [heavy_edges, node]
        const pq = [[0, source]]; 

        while (pq.length > 0) {
            // Pop element with smallest heavy_edges count
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > minHeavyEdges[u]) {
                continue;
            }

            if (d > k) {
                // Optimization: if current path already exceeds k, skip it
                continue;
            }

            if (u === target) {
                // Since Dijkstra explores in increasing order of 'd', the first time we reach target
                // gives the minimum number of heavy edges. If this minimum is <= k, we return true.
                // However, we must let Dijkstra finish or rely on the check at the end.
                // Since we prune if d > k, if we reach here, it's valid.
                // We continue to ensure all potential shorter paths are processed if we were not strictly limiting the PQ.
            }


            for (const { neighbor: v, cost } of adj[u]) {
                const new_heavy_edges = d + cost;

                if (new_heavy_edges <= k && new_heavy_edges < minHeavyEdges[v]) {
                    minHeavyEdges[v] = new_heavy_edges;
                    pq.push([new_heavy_edges, v]);
                }
            }
        }

        return minHeavyEdges[target] <= k;
    };

    // 3. Binary Search on the threshold T using the sorted unique weights.
    // We are looking for the smallest T in sortedWeights such that canReach(T) is true.

    let low = 0;
    let high = sortedWeights.length - 1;
    let result = -1;

    // Check if any path exists at all (using the maximum possible threshold, effectively all edges are light)
    const maxT = sortedWeights[sortedWeights.length - 1];
    if (!canReach(maxT)) {
        return -1;
    }

    // Binary search for the smallest T
    while (low <= high) {
        const midIndex = Math.floor((low + high) / 2);
        const T = sortedWeights[midIndex];

        if (canReach(T)) {
            // T works, try for a smaller threshold
            result = T;
            high = midIndex - 1;
        } else {
            // T is too small, need a larger threshold
            low = midIndex + 1;
        }
    }

    return result;
}

